document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll(".alert:not(.alert-permanent)").forEach(n=>{setTimeout(()=>{try{new bootstrap.Alert(n).close()}catch(t){}},5e3)});const n=window.location.pathname;document.querySelectorAll(".navbar-nav .nav-link").forEach(t=>{t.getAttribute("href")===n&&t.classList.add("active")});document.querySelectorAll(".needs-validation").forEach(n=>{n.addEventListener("submit",t=>{n.checkValidity()||(t.preventDefault(),t.stopPropagation()),n.classList.add("was-validated")},!1)});typeof $.fn.select2!="undefined"&&$(".js-select2").select2({placeholder:"Оберіть жанри...",allowClear:!0,width:"100%"});document.querySelectorAll("[data-confirm]").forEach(n=>{n.addEventListener("click",function(n){n.preventDefault();const i=this.dataset.confirm||"Ви впевнені?",t=this.closest("form");Swal.fire({icon:"warning",title:"Підтвердження",text:i,confirmButtonText:"Так",cancelButtonText:"Скасувати",showCancelButton:!0,confirmButtonColor:"#dc3545",cancelButtonColor:"#6c757d",reverseButtons:!0}).then(n=>{n.isConfirmed&&(t?t.submit():this.href&&(window.location.href=this.href))})})})});